#include <bits/stdc++.h>
using namespace std;
int n,d,dist[100005];
vector<int> g[100005];
int main(){
    scanf("%d%d",&n,&d);
    for(int i=1;i<n;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    int ans=0;
    queue<int> q;
    dist[1]=1,q.push(1);
    while(q.size()){
        int f=q.front(),len=g[f].size();
        q.pop();
        for(int i=0;i<len;i++)
            if(!dist[g[f][i]]){
                dist[g[f][i]]=dist[f]+1;
                ans++;
                if(dist[g[f][i]]<=d)
                    q.push(g[f][i]);
            }
    }
    printf("%d",ans);
    return 0;
}
